function syncWorkflowInputs(filename) {
    const appLabelInput = document.getElementById('tb-app-label');
    const fileNameInput = document.getElementById('tb-file-name');

    // Load persisted inputs for this specific workflow
    const configMap = JSON.parse(localStorage.getItem('conduit_workflow_configs') || '{}');
    const saved = configMap[filename] || {};

    appLabelInput.value = saved.app_label || '';
    fileNameInput.value = saved.file_name || '';

    // Auto-expand if there's data, otherwise collapse
    if (saved.app_label || saved.file_name) {
        toggleWorkflowExtras(true);
    } else {
        const extras = document.getElementById('tb-workflow-extras');
        const chevron = document.getElementById('tb-extras-chevron');
        extras.style.display = 'none';
        chevron.innerText = '▶';
        chevron.style.color = '';
    }
}

